"""Схема extract-настроек и сборка runtime config. Thin-wrapper над SettingsSchemaCollection. Формат payload: group_code -> values."""from __future__ import annotationsfrom pathlib import Pathfrom typing import Anyfrom ..models import ExtractConfigfrom ..providers.file_extract_provider import get_provider_settings_groupsfrom src.modules.settings_schema.models import SettingsSchemaCollectiondef _build_extract_schema_collection() -> SettingsSchemaCollection:    """Единая коллекция групп: провайдеры извлечения (PDF, изображения, текст, markdown, office)."""    provider_groups = get_provider_settings_groups()    return SettingsSchemaCollection(groups=provider_groups)# Ленивая сборка, чтобы избежать циклических импортов при первом обращении_EXTRACT_SCHEMA: SettingsSchemaCollection | None = Nonedef get_extract_settings_schema() -> SettingsSchemaCollection:    """Каноничная схема extract-настроек для GUI и нормализации."""    global _EXTRACT_SCHEMA    if _EXTRACT_SCHEMA is None:        _EXTRACT_SCHEMA = _build_extract_schema_collection()    return _EXTRACT_SCHEMAdef get_default_extract_payload() -> dict[str, dict[str, Any]]:    """Возвращает extract payload по умолчанию. Формат: group_code -> values."""    return get_extract_settings_schema().build_default_payload()def normalize_extract_payload(raw: dict[str, Any] | None) -> dict[str, dict[str, Any]]:    """    Нормализует сырой extract payload по схеме. Формат: group_code -> values.    При отсутствии или пустом raw возвращает payload по умолчанию.    """    if not raw or not isinstance(raw, dict):        return get_default_extract_payload()    return get_extract_settings_schema().normalize_payload(raw)def build_extract_config(    project_path: Path | str,    extract_payload: dict[str, Any] | None,    cache_path: Path | None = None,) -> ExtractConfig:    """    Строит ExtractConfig из extract payload.    Формат payload: group_code -> values (провайдеры на верхнем уровне).    Нормализация подставляет дефолты по схеме.    """    normalized = normalize_extract_payload(extract_payload)    schema = get_extract_settings_schema()    provider_configs: dict[str, dict[str, Any]] = {}    for group in schema.groups:        provider_configs[group.code] = dict(normalized.get(group.code) or {})    return ExtractConfig(        project_path=project_path,        provider_configs=provider_configs,        cache_path=cache_path,    )